  $catalog$::jsonb) as item(
    id text,
    title text,
    organization text,
    type text,
    countries jsonb,
    global boolean,
    location text,
    mode text,
    deadline text,
    url text
  )
)
insert into public.opportunities (
  id, title, organization, type, description, requirements, eligibility, benefits,
  country_codes, is_global, location, location_mode, deadline, application_url,
  canonical_url, source_name, source_url, status, published_at, last_verified_at
)
select
  id::uuid,
  title,
  organization,
  type::public.opportunity_type,
  title || ' is an officially published opportunity. Review the organizer page for complete current eligibility and application terms.',
  '{}'::text[],
  jsonb_build_object(
    'verificationDate', '2026-07-21',
    'deadlineKind', case when deadline is null then 'ongoing-or-self-paced' else 'fixed' end,
    'verificationNote', case
      when deadline is null then 'The official programme page documents ongoing vacancies or self-paced availability; individual vacancy terms may vary.'
      else 'The stored closing date was checked against the official source on the verification date.'
    end
  ),
  '{}'::text[],
  array(select jsonb_array_elements_text(countries)),
  global,
  location,
  mode::public.opportunity_location_mode,
  deadline::timestamptz,
  url,
  url,
  organization,
  url,
  'published'::public.opportunity_status,
  '2026-07-21T12:00:00Z'::timestamptz,
  '2026-07-21T12:00:00Z'::timestamptz
from catalog
on conflict (canonical_url) do nothing;
